            }
          ]
        },
        {
          "content": "fonların (Fonlar Merkezi Kayıt Kuruluşu nezdinde saklanmaktadır.) paraya çevrilmesi halinde değerinin satış anındaki borsa fiyatına göre belirleneceğini ve vergi, fon vb. gibi yasal yükümlülüklerin kesileceğini",
          "polygon": [
            {
              "x": 0.4933,
              "y": 10.4174
            },
            {
              "x": 7.772,
              "y": 10.418
            },
